     1→import ScreenCaptureKit
     2→import SwiftUI
     3→
     4→@main
     5→struct PabloCompanionApp: App {
     6→    var body: some Scene {
     7→        WindowGroup {
     8→            ContentView()
     9→                .task {
    10→                    await requestScreenCapturePermission()
    11→                }
    12→        }
    13→        .windowResizability(.contentMinSize)
    14→    }
    15→
    16→    /// Triggers the ScreenCaptureKit permission prompt, which reliably
    17→    /// registers the app in System Settings > Privacy & Security >
    18→    /// Screen & System Audio Recording.
    19→    private func requestScreenCapturePermission() async {
    20→        do {
    21→            // This call triggers the system permission prompt on first launch.
    22→            // It will throw if permission is denied, which is fine — we handle
    23→            // that gracefully in the capture layer.
    24→            _ = try await SCShareableContent.excludingDesktopWindows(
    25→                false, onScreenWindowsOnly: false
    26→            )
    27→        } catch {
    28→            // Expected on first launch before permission is granted
    29→        }
    30→    }
    31→}
