   113→/// A vertical audio level meter.
   114→struct LevelMeter: View {
   115→    let label: String
   116→    let level: Float
   117→
   118→    var body: some View {
   119→        VStack(spacing: 4) {
   120→            GeometryReader { geometry in
   121→                ZStack(alignment: .bottom) {
   122→                    RoundedRectangle(cornerRadius: 4)
   123→                        .fill(.quaternary)
   124→
   125→                    RoundedRectangle(cornerRadius: 4)
   126→                        .fill(levelColor)
   127→                        .frame(
   128→                            height: max(
   129→                                0,
   130→                                geometry.size.height * CGFloat(clampedLevel)
   131→                            )
   132→                        )
   133→                }
   134→            }
   135→            .frame(width: 24)
   136→
   137→            Text(label)
   138→                .font(.caption2)
   139→                .foregroundStyle(.secondary)
   140→        }
   141→    }
   142→
   143→    private var clampedLevel: Float {
   144→        min(max(level, 0), 1)
   145→    }
   146→
   147→    private var levelColor: Color {
   148→        if clampedLevel > 0.8 {
   149→            return .red
   150→        } else if clampedLevel > 0.5 {
   151→            return .yellow
   152→        } else {
   153→            return .green
   154→        }
   155→    }
   156→}
