import Foundation
import os

/// A simple URLSession wrapper for communicating with the sample backend.
@MainActor
final class APIClient: Sendable {
    private let logger = Logger(subsystem: "com.macos-sample", category: "APIClient")

    nonisolated var baseURL: URL {
        URL(string: _baseURLString)!
    }

    private let _baseURLString: String
    private let clientType = "therapyrecorder-macos/1.0"

    /// Optional closure to provide a Bearer token for authenticated requests.
    var getToken: (@Sendable () async throws -> String)?

    init(baseURL: String = "http://localhost:8000") {
        self._baseURLString = baseURL
    }

    /// Checks if the backend is reachable.
    func healthCheck() async throws -> Bool {
        let url = baseURL.appendingPathComponent("health")
        var request = URLRequest(url: url)
        request.setValue(clientType, forHTTPHeaderField: "X-Client-Type")
        let (_, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else { return false }
        return httpResponse.statusCode == 200
    }

    /// Uploads a recording file to the backend via multipart form data.
    /// Returns a progress-reporting async stream and the final upload response.
    func uploadRecording(
        fileURL: URL,
        onProgress: @Sendable @escaping (Double) -> Void
    ) async throws -> UploadResponse {
        let url = baseURL.appendingPathComponent("api/recordings/upload")

        let boundary = UUID().uuidString
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue(
            "multipart/form-data; boundary=\(boundary)",
            forHTTPHeaderField: "Content-Type"
        )
        request.setValue(clientType, forHTTPHeaderField: "X-Client-Type")

        // Inject Bearer token if available
        if let getToken {
            let token = try await getToken()
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let fileData = try Data(contentsOf: fileURL)
        let body = createMultipartBody(
            fileData: fileData,
            fileName: fileURL.lastPathComponent,
            boundary: boundary
        )
        request.httpBody = body

        logger.info("Uploading \(fileURL.lastPathComponent) (\(fileData.count) bytes)")

        // Simulate incremental progress since URLSession data tasks
        // don't provide upload progress natively without a delegate.
        onProgress(0.3)

        let (data, response) = try await URLSession.shared.data(for: request)

        onProgress(1.0)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let body = String(data: data, encoding: .utf8) ?? "Unknown error"
            logger.error("Upload failed: \(httpResponse.statusCode) — \(body)")
            throw APIError.serverError(statusCode: httpResponse.statusCode, message: body)
        }

        let decoded = try JSONDecoder().decode(UploadResponse.self, from: data)
        logger.info("Upload successful: \(decoded.id)")
        return decoded
    }

    /// Fetches a paginated list of patients from the backend.
    func fetchPatients(
        search: String = "",
        page: Int = 1,
        pageSize: Int = 50
    ) async throws -> PatientListResponse {
        var components = URLComponents(
            url: baseURL.appendingPathComponent("api/patients"),
            resolvingAgainstBaseURL: false
        )!
        components.queryItems = [
            URLQueryItem(name: "search", value: search),
            URLQueryItem(name: "page", value: String(page)),
            URLQueryItem(name: "page_size", value: String(pageSize)),
        ]

        var request = URLRequest(url: components.url!)
        request.setValue(clientType, forHTTPHeaderField: "X-Client-Type")

        if let getToken {
            let token = try await getToken()
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let body = String(data: data, encoding: .utf8) ?? "Unknown error"
            logger.error("Fetch patients failed: \(httpResponse.statusCode) — \(body)")
            throw APIError.serverError(statusCode: httpResponse.statusCode, message: body)
        }

        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        return try decoder.decode(PatientListResponse.self, from: data)
    }

    private func createMultipartBody(
        fileData: Data,
        fileName: String,
        boundary: String
    ) -> Data {
        var body = Data()

        body.append("--\(boundary)\r\n")
        body.append("Content-Disposition: form-data; name=\"file\"; filename=\"\(fileName)\"\r\n")
        body.append("Content-Type: application/octet-stream\r\n\r\n")
        body.append(fileData)
        body.append("\r\n")
        body.append("--\(boundary)--\r\n")

        return body
    }
}

enum APIError: LocalizedError {
    case invalidResponse
    case serverError(statusCode: Int, message: String)

    var errorDescription: String? {
        switch self {
        case .invalidResponse:
            "Invalid response from server."
        case let .serverError(code, message):
            "Server error (\(code)): \(message)"
        }
    }
}

struct UploadResponse: Codable, Sendable {
    let id: String
    let status: String
}

/// Server configuration returned by the therapy-assistant-platform's /api/config endpoint.
struct ServerConfig: Codable, Sendable {
    let apiUrl: String
    let firebaseApiKey: String?
    let firebaseProjectId: String?
}

/// Fetches runtime configuration from the therapy-assistant-platform.
/// This discovers the backend API URL so the user doesn't have to enter it manually.
func fetchServerConfig(authServerURL: String) async throws -> ServerConfig {
    let base = authServerURL.trimmingCharacters(in: CharacterSet(charactersIn: "/"))
    guard let url = URL(string: "\(base)/api/config") else {
        throw APIError.invalidResponse
    }
    let (data, response) = try await URLSession.shared.data(from: url)
    guard let httpResponse = response as? HTTPURLResponse,
          (200 ... 299).contains(httpResponse.statusCode)
    else {
        throw APIError.invalidResponse
    }
    return try JSONDecoder().decode(ServerConfig.self, from: data)
}

extension Data {
    fileprivate mutating func append(_ string: String) {
        if let data = string.data(using: .utf8) {
            append(data)
        }
    }
}

import AuthenticationServices
import Foundation
import os
import SwiftUI

/// Manages authentication state via ASWebAuthenticationSession and Firebase token refresh.
@MainActor
@Observable
final class AuthViewModel {
    // MARK: - Auth State

    enum AuthState: Equatable {
        case unauthenticated
        case authenticating
        case authenticated(email: String)
        case tokenExpired
    }

    var authState: AuthState = .unauthenticated
    var errorMessage: String?

    @ObservationIgnored
    @AppStorage("authServerURL") var authServerURL = "http://localhost:3000"

    @ObservationIgnored
    @AppStorage("backendAPIURL") var backendAPIURL = "http://localhost:8000"

    @ObservationIgnored
    @AppStorage("firebaseAPIKey") var firebaseAPIKey = ""

    @ObservationIgnored
    @AppStorage("tokenExpiry") private var tokenExpiryTimestamp: Double = 0

    /// Convenience accessor for the email when authenticated.
    var authenticatedEmail: String {
        if case let .authenticated(email) = authState {
            return email
        }
        return ""
    }

    private let logger = Logger(subsystem: "com.macos-sample", category: "AuthViewModel")

    // MARK: - Init

    init() {
        restoreAuthState()
    }

    // MARK: - Sign In

    func signIn() {
        guard let url = buildAuthURL() else {
            errorMessage = "Invalid auth server URL."
            return
        }

        authState = .authenticating
        errorMessage = nil

        // Launch from a file-scope free function that creates the completion
        // closure internally, so it is NOT defined in a @MainActor context.
        // This prevents Swift 6 from inserting a runtime isolation assert
        // (dispatch_assert_queue_fail) when the framework calls back on an
        // XPC thread. See: https://github.com/swiftlang/swift/issues/75453
        launchWebAuthSession(url: url, viewModel: self)
        logger.info("ASWebAuthenticationSession started")
    }

    // MARK: - Sign Out

    func signOut() {
        KeychainManager.deleteAll()
        tokenExpiryTimestamp = 0
        authState = .unauthenticated
        errorMessage = nil
        logger.info("User signed out")
    }

    // MARK: - Token Access

    /// Returns a valid ID token, refreshing if needed. Throws on failure.
    func getValidToken() async throws -> String {
        guard let idToken = KeychainManager.getToken(forKey: .idToken) else {
            authState = .tokenExpired
            throw TokenError.noToken
        }

        // Refresh if within 5-minute buffer of expiry
        let expiryDate = Date(timeIntervalSince1970: tokenExpiryTimestamp)
        if Date().addingTimeInterval(5 * 60) >= expiryDate {
            return try await refreshToken()
        }

        return idToken
    }

    // MARK: - Private

    private func restoreAuthState() {
        guard let idToken = KeychainManager.getToken(forKey: .idToken),
              let email = KeychainManager.getToken(forKey: .userEmail)
        else {
            authState = .unauthenticated
            return
        }

        // Restore auth server URL from Keychain
        if let savedURL = KeychainManager.getToken(forKey: .authServerURL) {
            authServerURL = savedURL
        }

        let expiryDate = Date(timeIntervalSince1970: tokenExpiryTimestamp)
        if Date().addingTimeInterval(5 * 60) >= expiryDate {
            // Token expired or close to it — check if we can refresh
            if KeychainManager.getToken(forKey: .refreshToken) != nil {
                authState = .authenticated(email: email)
                logger.info("Restored auth state for \(email) (token needs refresh)")
            } else {
                authState = .tokenExpired
                logger.info("Token expired and no refresh token available")
            }
        } else {
            authState = .authenticated(email: email)
            logger.info("Restored auth state for \(email), token valid")
        }

        // Also update expiry from JWT if we have a fresh token
        if let expiry = extractExpiry(from: idToken) {
            tokenExpiryTimestamp = expiry.timeIntervalSince1970
        }
    }

    private func buildAuthURL() -> URL? {
        let base = authServerURL.trimmingCharacters(in: .init(charactersIn: "/"))
        let redirectURI = "therapyrecorder://callback"
        return URL(string: "\(base)/native-auth?redirect_uri=\(redirectURI)")
    }

    fileprivate func handleAuthCallback(callbackURL: URL?, error: (any Error)?) {
        if let error {
            if (error as NSError).code == ASWebAuthenticationSessionError.canceledLogin.rawValue {
                logger.info("User cancelled sign in")
                authState = .unauthenticated
                return
            }
            logger.error("Auth error: \(error.localizedDescription)")
            errorMessage = error.localizedDescription
            authState = .unauthenticated
            return
        }

        guard let callbackURL,
              let components = URLComponents(url: callbackURL, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems
        else {
            errorMessage = "Invalid callback URL."
            authState = .unauthenticated
            return
        }

        let params = Dictionary(uniqueKeysWithValues: queryItems.compactMap { item in
            item.value.map { (item.name, $0) }
        })

        guard let idToken = params["id_token"],
              let refreshToken = params["refresh_token"]
        else {
            errorMessage = "Missing tokens in callback."
            authState = .unauthenticated
            return
        }

        // Store tokens and auth server URL for session restore
        KeychainManager.saveToken(idToken, forKey: .idToken)
        KeychainManager.saveToken(refreshToken, forKey: .refreshToken)
        KeychainManager.saveToken(authServerURL, forKey: .authServerURL)

        // Extract email from JWT
        let email = extractEmail(from: idToken) ?? params["email"] ?? "Unknown"
        KeychainManager.saveToken(email, forKey: .userEmail)

        // Extract and store expiry
        if let expiry = extractExpiry(from: idToken) {
            tokenExpiryTimestamp = expiry.timeIntervalSince1970
        }

        authState = .authenticated(email: email)
        errorMessage = nil
        logger.info("Signed in as \(email)")
    }

    private func refreshToken() async throws -> String {
        guard let refreshToken = KeychainManager.getToken(forKey: .refreshToken) else {
            authState = .tokenExpired
            throw TokenError.noRefreshToken
        }

        guard !firebaseAPIKey.isEmpty else {
            throw TokenError.noAPIKey
        }

        let refresher = TokenRefresher(apiKey: firebaseAPIKey)
        do {
            let response = try await refresher.refresh(using: refreshToken)

            KeychainManager.saveToken(response.idToken, forKey: .idToken)
            KeychainManager.saveToken(response.refreshToken, forKey: .refreshToken)
            tokenExpiryTimestamp = Date().addingTimeInterval(Double(response.expiresIn)).timeIntervalSince1970

            // Update email if it changed
            if let email = extractEmail(from: response.idToken) {
                KeychainManager.saveToken(email, forKey: .userEmail)
                authState = .authenticated(email: email)
            }

            return response.idToken
        } catch let refreshError as TokenRefresher.RefreshError {
            authState = .tokenExpired
            throw refreshError
        }
    }

    // MARK: - JWT Helpers

    func extractExpiry(from idToken: String) -> Date? {
        guard let payload = decodeJWTPayload(idToken),
              let exp = payload["exp"] as? TimeInterval
        else { return nil }
        return Date(timeIntervalSince1970: exp)
    }

    private func extractEmail(from idToken: String) -> String? {
        guard let payload = decodeJWTPayload(idToken) else { return nil }
        return payload["email"] as? String
    }

    private func decodeJWTPayload(_ jwt: String) -> [String: Any]? {
        let parts = jwt.split(separator: ".")
        guard parts.count >= 2 else { return nil }

        var base64 = String(parts[1])
            .replacingOccurrences(of: "-", with: "+")
            .replacingOccurrences(of: "_", with: "/")

        // Pad to multiple of 4
        let remainder = base64.count % 4
        if remainder > 0 {
            base64 += String(repeating: "=", count: 4 - remainder)
        }

        guard let data = Data(base64Encoded: base64),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any]
        else { return nil }

        return json
    }
}

// MARK: - Errors

enum TokenError: LocalizedError {
    case noToken
    case noRefreshToken
    case noAPIKey

    var errorDescription: String? {
        switch self {
        case .noToken:
            "No authentication token found. Please sign in."
        case .noRefreshToken:
            "Session expired. Please sign in again."
        case .noAPIKey:
            "Firebase API key not configured."
        }
    }
}

// MARK: - Web Auth Session Launcher

/// Sendable wrapper for weak references that cross isolation boundaries.
private struct WeakRef<T: AnyObject>: @unchecked Sendable {
    weak var value: T?
}

/// Launches ASWebAuthenticationSession from a nonisolated (file-scope) context
/// so the completion closure doesn't inherit @MainActor isolation and crash
/// when the framework calls back on an XPC thread. (swiftlang/swift#75453)
private func launchWebAuthSession(url: URL, viewModel: AuthViewModel) {
    let ref = WeakRef(value: viewModel)
    let contextProvider = WebAuthContextProvider()
    let session = ASWebAuthenticationSession(
        url: url,
        callbackURLScheme: "therapyrecorder"
    ) { callbackURL, error in
        Task { @MainActor in
            ref.value?.handleAuthCallback(callbackURL: callbackURL, error: error)
        }
    }
    session.presentationContextProvider = contextProvider
    session.prefersEphemeralWebBrowserSession = false
    _ = contextProvider
    session.start()
}

// MARK: - ASWebAuthenticationPresentationContextProviding

private final class WebAuthContextProvider: NSObject, @preconcurrency ASWebAuthenticationPresentationContextProviding {
    func presentationAnchor(for _: ASWebAuthenticationSession) -> ASPresentationAnchor {
        // swiftlint:disable:next force_unwrapping
        NSApplication.shared.keyWindow ?? NSApplication.shared.windows.first!
    }
}

import Foundation
import os

/// Refreshes Firebase ID tokens using the securetoken.googleapis.com REST API.
struct TokenRefresher: Sendable {
    struct TokenResponse: Sendable {
        let idToken: String
        let refreshToken: String
        let expiresIn: Int
    }

    enum RefreshError: LocalizedError {
        case networkError(underlying: any Error)
        case invalidResponse
        case tokenRevoked
        case userDisabled
        case serverError(message: String)

        var errorDescription: String? {
            switch self {
            case let .networkError(error):
                "Network error: \(error.localizedDescription)"
            case .invalidResponse:
                "Invalid response from token service."
            case .tokenRevoked:
                "Your session has expired. Please sign in again."
            case .userDisabled:
                "This account has been disabled."
            case let .serverError(message):
                "Token refresh failed: \(message)"
            }
        }
    }

    private let apiKey: String
    private let logger = Logger(subsystem: "com.macos-sample", category: "TokenRefresher")

    init(apiKey: String) {
        self.apiKey = apiKey
    }

    func refresh(using refreshToken: String) async throws -> TokenResponse {
        let urlString = "https://securetoken.googleapis.com/v1/token?key=\(apiKey)"
        guard let url = URL(string: urlString) else {
            throw RefreshError.invalidResponse
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/x-www-form-urlencoded", forHTTPHeaderField: "Content-Type")
        request.httpBody = "grant_type=refresh_token&refresh_token=\(refreshToken)"
            .data(using: .utf8)

        let data: Data
        let response: URLResponse
        do {
            (data, response) = try await URLSession.shared.data(for: request)
        } catch {
            throw RefreshError.networkError(underlying: error)
        }

        guard let httpResponse = response as? HTTPURLResponse else {
            throw RefreshError.invalidResponse
        }

        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let body = try? JSONSerialization.jsonObject(with: data) as? [String: Any]
            let errorMessage = (body?["error"] as? [String: Any])?["message"] as? String ?? "Unknown"

            switch errorMessage {
            case "TOKEN_EXPIRED", "INVALID_REFRESH_TOKEN":
                throw RefreshError.tokenRevoked
            case "USER_DISABLED":
                throw RefreshError.userDisabled
            default:
                throw RefreshError.serverError(message: errorMessage)
            }
        }

        guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let idToken = json["id_token"] as? String,
              let newRefreshToken = json["refresh_token"] as? String,
              let expiresInString = json["expires_in"] as? String,
              let expiresIn = Int(expiresInString)
        else {
            throw RefreshError.invalidResponse
        }

        logger.info("Token refreshed successfully, expires in \(expiresIn)s")
        return TokenResponse(
            idToken: idToken,
            refreshToken: newRefreshToken,
            expiresIn: expiresIn
        )
    }
}

import AudioCaptureKit
import Crypto
import Foundation

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║  WARNING: DEMO ONLY — DO NOT USE IN PRODUCTION                         ║
// ║                                                                        ║
// ║  This encryptor uses a hardcoded key for demonstration purposes.       ║
// ║  In a production application, encryption keys must be:                 ║
// ║    - Generated per-user or per-session                                 ║
// ║    - Stored securely in the macOS Keychain                             ║
// ║    - Never committed to source control                                 ║
// ║    - Rotated on a regular schedule                                     ║
// ║                                                                        ║
// ║  This exists solely to demonstrate the AudioCaptureKit encryption      ║
// ║  pipeline in the sample app.                                           ║
// ╚══════════════════════════════════════════════════════════════════════════╝

/// A demonstration encryptor that uses AES-256-GCM with a hardcoded key.
struct DemoEncryptor: CaptureEncryptor {
    /// WARNING: Hardcoded demo key — NOT for production use.
    private static let demoKeyBytes: [UInt8] = [
        0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08,
        0x09, 0x0A, 0x0B, 0x0C, 0x0D, 0x0E, 0x0F, 0x10,
        0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18,
        0x19, 0x1A, 0x1B, 0x1C, 0x1D, 0x1E, 0x1F, 0x20,
    ]

    private let key: SymmetricKey

    init() {
        self.key = SymmetricKey(data: Self.demoKeyBytes)
    }

    var algorithm: String {
        "AES-256-GCM"
    }

    func encrypt(_ data: Data) throws -> Data {
        do {
            let sealedBox = try AES.GCM.seal(data, using: key)
            guard let combined = sealedBox.combined else {
                throw CaptureError.encryptionFailed("Failed to produce combined sealed box")
            }
            return combined
        } catch let error as CaptureError {
            throw error
        } catch {
            throw CaptureError.encryptionFailed(error.localizedDescription)
        }
    }

    func decrypt(_ data: Data) throws -> Data {
        do {
            let sealedBox = try AES.GCM.SealedBox(combined: data)
            return try AES.GCM.open(sealedBox, using: key)
        } catch {
            throw CaptureError.encryptionFailed("Decryption failed: \(error.localizedDescription)")
        }
    }

    /// Decrypts an encrypted WAV file and returns complete in-memory WAV data.
    ///
    /// File format: 44-byte WAV header followed by encrypted chunks.
    /// Each chunk: 4-byte UInt32 length prefix (little-endian) + combined sealed box data.
    static func decryptFile(at url: URL) throws -> Data {
        let fileData = try Data(contentsOf: url)
        let headerSize = 44
        guard fileData.count > headerSize else {
            throw CaptureError.encryptionFailed("File too small to contain WAV header")
        }

        let header = fileData.prefix(headerSize)
        var offset = headerSize
        let encryptor = DemoEncryptor()
        var pcmData = Data()

        while offset + 4 <= fileData.count {
            let lengthBytes = fileData[offset ..< offset + 4]
            let chunkLength = lengthBytes.withUnsafeBytes { $0.load(as: UInt32.self) }
            let length = Int(UInt32(littleEndian: chunkLength))
            offset += 4

            guard offset + length <= fileData.count else {
                throw CaptureError.encryptionFailed("Encrypted chunk exceeds file bounds")
            }

            let chunkData = fileData[offset ..< offset + length]
            let decrypted = try encryptor.decrypt(Data(chunkData))
            pcmData.append(decrypted)
            offset += length
        }

        // Rebuild WAV with correct data size in header
        var wav = Data(header)
        let dataSize = UInt32(pcmData.count)
        let fileSize = UInt32(36 + pcmData.count)
        // Update RIFF chunk size (bytes 4-7)
        wav.replaceSubrange(4 ..< 8, with: withUnsafeBytes(of: fileSize.littleEndian) { Data($0) })
        // Update data sub-chunk size (bytes 40-43)
        wav.replaceSubrange(40 ..< 44, with: withUnsafeBytes(of: dataSize.littleEndian) { Data($0) })
        wav.append(pcmData)

        return wav
    }

    func keyMetadata() -> [String: String] {
        [
            "keyId": "demo-key-v1",
            "algorithm": algorithm,
            "warning": "DEMO KEY — NOT FOR PRODUCTION",
        ]
    }
}

import AudioCaptureKit
import AVFoundation
import CoreAudio
import CoreGraphics
import Foundation
import os

/// Manages the recording lifecycle using CompositeCaptureSession.
@MainActor
@Observable
final class RecordingViewModel {
    // MARK: - Published State

    var recordingState: RecordingUIState = .idle
    var micLevel: Float = 0
    var systemLevel: Float = 0
    var peakMicLevel: Float = 0
    var peakSystemLevel: Float = 0
    var duration: TimeInterval = 0
    var recordings: [LocalRecording] = []
    var availableMics: [AudioSource] = []
    var selectedMicID: String? {
        didSet { checkBluetoothRoutingConflict() }
    }

    var encryptionEnabled = true
    var errorMessage: String?
    var showError = false
    var playingRecordingID: UUID?
    var systemAudioActive = false
    var bluetoothRoutingConflict = false
    var bluetoothRecommendation: String?
    var systemAudioPermitted: Bool = CGPreflightScreenCaptureAccess()

    // MARK: - Debug / Diagnostics

    var debugEnableMic = true
    var debugEnableSystem = true
    var debugDiagnostics: CaptureSessionDiagnostics = .init()

    // MARK: - Private

    private var session: CompositeCaptureSession?
    private var audioPlayer: AVAudioPlayer?
    private let playerDelegate = AudioPlayerDelegateAdapter()
    private let logger = Logger(subsystem: "com.macos-sample", category: "RecordingViewModel")
    private let delegateAdapter = CaptureDelegateAdapter()
    private var deviceChangeListenerInstalled = false
    private var systemAudioAvailableAtStart = false

    // MARK: - Recording Controls

    func loadAudioSources() async {
        systemAudioPermitted = CGPreflightScreenCaptureAccess()
        await refreshAudioSources()
        installDeviceChangeListener()
    }

    /// Queries available audio sources and updates the mic list.
    private func refreshAudioSources() async {
        let tempSession = CompositeCaptureSession(
            configuration: CaptureConfiguration(outputDirectory: recordingsDirectory)
        )
        do {
            let sources = try await tempSession.availableAudioSources()
            let previousSelection = selectedMicID
            availableMics = sources.filter { $0.type == .mic }
            let systemSources = sources.filter { $0.type == .system }
            systemAudioAvailableAtStart = !systemSources.isEmpty

            // Preserve selection if the device is still available, otherwise pick default
            if let previousSelection, availableMics.contains(where: { $0.id == previousSelection }) {
                selectedMicID = previousSelection
            } else {
                selectedMicID = availableMics.first(where: { $0.isDefault })?.id
                    ?? availableMics.first?.id
            }
            logger
                .info(
                    "Audio sources refreshed: \(self.availableMics.count) mic(s), system audio available: \(self.systemAudioAvailableAtStart)"
                )
            checkBluetoothRoutingConflict()
        } catch {
            logger.error("Failed to load audio sources: \(error.localizedDescription)")
            showErrorAlert("Failed to load audio sources: \(error.localizedDescription)")
        }
    }

    /// Listens for Core Audio device additions/removals and refreshes the mic list.
    private func installDeviceChangeListener() {
        guard !deviceChangeListenerInstalled else { return }

        var address = AudioObjectPropertyAddress(
            mSelector: kAudioHardwarePropertyDevices,
            mScope: kAudioObjectPropertyScopeGlobal,
            mElement: kAudioObjectPropertyElementMain
        )

        // The listener block fires on an arbitrary CoreAudio queue.
        // In Swift 6, closures inherit the actor isolation of the enclosing
        // context — so a bare `{ _, _ in }` here would be @MainActor-isolated
        // and crash with _dispatch_assert_queue_fail when CoreAudio calls it.
        // We break that by declaring the block as an explicit @Sendable variable.
        let weakSelf = WeakSendableBox(self)

        let listenerBlock: @Sendable (UInt32, UnsafePointer<AudioObjectPropertyAddress>) -> Void = { _, _ in
            DispatchQueue.main.async {
                Task { @MainActor in
                    guard let viewModel = weakSelf.value else { return }
                    viewModel.logger.info("Audio device change detected, refreshing sources")

                    // Only stop recording if the selected mic actually disappeared.
                    // Device additions (e.g. aggregate device created by system audio
                    // capture) should not interrupt an active recording.
                    if viewModel.recordingState == .recording || viewModel.recordingState == .paused {
                        if let micID = viewModel.selectedMicID,
                           !viewModel.isMicStillAvailable(micID)
                        {
                            viewModel.logger.warning("Selected mic \(micID) disconnected during recording, stopping")
                            await viewModel.stopRecording()
                            viewModel.showErrorAlert("Recording stopped: microphone was disconnected")
                        } else {
                            viewModel.logger.info("Device change during recording, but selected mic still available")
                        }
                    }

                    if viewModel.playingRecordingID != nil {
                        viewModel.logger.info("Device changed during playback, stopping playback")
                        viewModel.stopPlayback()
                    }

                    await viewModel.refreshAudioSources()
                }
            }
        }

        let status = AudioObjectAddPropertyListenerBlock(
            AudioObjectID(kAudioObjectSystemObject),
            &address,
            nil,
            listenerBlock
        )

        if status == noErr {
            deviceChangeListenerInstalled = true
            logger.info("Audio device change listener installed")
        } else {
            logger.error("Failed to install audio device change listener: \(status)")
        }
    }

    func startRecording() async {
        logger.info("Starting recording – system audio available at source check: \(self.systemAudioAvailableAtStart)")

        let encryptor: DemoEncryptor? = encryptionEnabled ? DemoEncryptor() : nil
        let config = CaptureConfiguration(
            sampleRate: 48000,
            bitDepth: 16,
            channels: 2,
            encryptor: encryptor,
            outputDirectory: recordingsDirectory,
            micDeviceID: selectedMicID,
            enableMicCapture: debugEnableMic,
            enableSystemCapture: debugEnableSystem
        )

        let captureSession = CompositeCaptureSession(configuration: config)
        self.session = captureSession

        delegateAdapter.onStateChange = { [weak self] state in
            Task { @MainActor in
                self?.handleStateChange(state)
            }
        }
        delegateAdapter.onLevelsUpdate = { [weak self] levels in
            Task { @MainActor in
                self?.micLevel = levels.micLevel
                self?.systemLevel = levels.systemLevel
                self?.peakMicLevel = levels.peakMicLevel
                self?.peakSystemLevel = levels.peakSystemLevel
            }
        }
        delegateAdapter.onError = { [weak self] error in
            Task { @MainActor in
                guard let self else { return }
                self.logger.error("Capture error: \(error.localizedDescription)")
                // System audio config errors are non-fatal — recording continues with mic only
                if case let .configurationFailed(msg) = error,
                   msg.contains("System audio")
                {
                    self.systemAudioActive = false
                    self.logger.warning("System audio not available, recording mic only")
                }
                self.showErrorAlert(error.localizedDescription)
            }
        }
        captureSession.delegate = delegateAdapter

        do {
            try captureSession.configure(config)
            try await captureSession.startCapture()
            recordingState = .recording
            systemAudioActive = systemAudioAvailableAtStart
            logger.info("Recording started – systemAudioActive: \(self.systemAudioActive)")
        } catch {
            logger.error("Failed to start recording: \(error.localizedDescription)")
            showErrorAlert("Failed to start recording: \(error.localizedDescription)")
            recordingState = .idle
            systemAudioActive = false
        }
    }

    func pauseRecording() {
        guard let session else { return }
        do {
            try session.pauseCapture()
            recordingState = .paused
            logger.info("Recording paused")
        } catch {
            logger.error("Failed to pause: \(error.localizedDescription)")
            showErrorAlert("Failed to pause: \(error.localizedDescription)")
        }
    }

    func resumeRecording() {
        guard let session else { return }
        do {
            try session.resumeCapture()
            recordingState = .recording
            logger.info("Recording resumed")
        } catch {
            logger.error("Failed to resume: \(error.localizedDescription)")
            showErrorAlert("Failed to resume: \(error.localizedDescription)")
        }
    }

    func stopRecording() async {
        guard let session else { return }
        do {
            let result = try await session.stopCapture()
            logger.info("Recording stopped: \(result.fileURL.lastPathComponent)")

            let recording = LocalRecording(
                id: result.metadata.id,
                fileURL: result.fileURL,
                duration: result.duration,
                createdAt: Date(),
                isEncrypted: result.metadata.isEncrypted,
                checksum: result.checksum,
                isUploaded: false
            )
            recordings.insert(recording, at: 0)
            recordingState = .idle
            resetLevels()
        } catch {
            logger.error("Failed to stop recording: \(error.localizedDescription)")
            showErrorAlert("Failed to stop recording: \(error.localizedDescription)")
            recordingState = .idle
            resetLevels()
        }
        systemAudioActive = false
        self.session = nil
    }

    // MARK: - Test Tone

    /// Generates a 3-second test tone recording (440Hz left, 880Hz right)
    /// that bypasses all capture. Proves the file writing + playback path works.
    func generateTestTone() {
        let sampleRate: Double = 48000
        let durationSecs = 3.0
        let frameCount = Int(sampleRate * durationSecs)

        // Generate stereo interleaved: 440Hz sine in left, 880Hz sine in right
        var stereo = [Float](repeating: 0, count: frameCount * 2)
        for i in 0 ..< frameCount {
            let t = Float(i) / Float(sampleRate)
            stereo[i * 2] = 0.5 * sin(2.0 * .pi * 440.0 * t) // Left: 440Hz
            stereo[i * 2 + 1] = 0.5 * sin(2.0 * .pi * 880.0 * t) // Right: 880Hz
        }

        // Convert to 16-bit PCM
        var pcmData = Data(capacity: stereo.count * 2)
        for sample in stereo {
            let clamped = max(-1.0, min(1.0, sample))
            var int16 = Int16(clamped * Float(Int16.max))
            withUnsafeBytes(of: &int16) { pcmData.append(contentsOf: $0) }
        }

        // Write WAV file
        let header = AudioFormatConverter.generateWAVHeader(
            sampleRate: UInt32(sampleRate),
            bitDepth: 16,
            channels: 2,
            dataSize: UInt32(pcmData.count)
        )

        let fileName = "test_tone_\(UUID().uuidString).wav"
        let fileURL = recordingsDirectory.appendingPathComponent(fileName)
        do {
            var wavData = header
            wavData.append(pcmData)
            try wavData.write(to: fileURL)

            let recording = LocalRecording(
                id: UUID(),
                fileURL: fileURL,
                duration: durationSecs,
                createdAt: Date(),
                isEncrypted: false,
                checksum: "test-tone",
                isUploaded: false
            )
            recordings.insert(recording, at: 0)
            logger.info("Test tone generated: \(fileName)")
        } catch {
            showErrorAlert("Failed to generate test tone: \(error.localizedDescription)")
        }
    }

    // MARK: - Playback

    func playRecording(_ recording: LocalRecording) {
        stopPlayback()

        do {
            let player: AVAudioPlayer
            if recording.isEncrypted {
                let wavData = try DemoEncryptor.decryptFile(at: recording.fileURL)
                player = try AVAudioPlayer(data: wavData)
            } else {
                player = try AVAudioPlayer(contentsOf: recording.fileURL)
            }

            playerDelegate.onFinish = { [weak self] in
                Task { @MainActor in
                    self?.playingRecordingID = nil
                    self?.audioPlayer = nil
                }
            }
            player.delegate = playerDelegate
            player.play()
            audioPlayer = player
            playingRecordingID = recording.id
        } catch {
            logger.error("Playback failed: \(error.localizedDescription)")
            showErrorAlert("Playback failed: \(error.localizedDescription)")
        }
    }

    func stopPlayback() {
        audioPlayer?.stop()
        audioPlayer = nil
        playingRecordingID = nil
    }

    // MARK: - Helpers

    private func handleStateChange(_ state: CaptureState) {
        logger.debug("State change: \(String(describing: state)), systemAudioActive: \(self.systemAudioActive)")
        switch state {
        case .idle:
            recordingState = .idle
            duration = 0
        case let .capturing(elapsed):
            recordingState = .recording
            duration = elapsed
            // Poll diagnostics from the session
            if let session {
                debugDiagnostics = session.diagnostics
            }
        case let .paused(elapsed):
            recordingState = .paused
            duration = elapsed
        case .stopping:
            recordingState = .idle
            // Final diagnostics snapshot
            if let session {
                debugDiagnostics = session.diagnostics
            }
        case let .failed(error):
            recordingState = .idle
            systemAudioActive = false
            showErrorAlert(error.localizedDescription)
        default:
            break
        }
    }

    private func resetLevels() {
        micLevel = 0
        systemLevel = 0
        peakMicLevel = 0
        peakSystemLevel = 0
        duration = 0
        systemAudioActive = false
    }

    private func showErrorAlert(_ message: String) {
        errorMessage = message
        showError = true
    }

    /// Checks if the selected mic is a Bluetooth device that also serves as the current output,
    /// which would force macOS into HFP mode (mono ~16kHz).
    private func checkBluetoothRoutingConflict() {
        guard let selectedMicID,
              let mic = availableMics.first(where: { $0.id == selectedMicID }),
              mic.transportType == .bluetooth || mic.transportType == .bluetoothLE
        else {
            bluetoothRoutingConflict = false
            bluetoothRecommendation = nil
            return
        }

        guard let outputUID = Self.defaultOutputDeviceUID() else {
            bluetoothRoutingConflict = false
            bluetoothRecommendation = nil
            return
        }

        // Compare the UID prefix — Bluetooth input/output devices share the same base UID
        // but may have different suffixes (e.g. ":input" / ":output"). A prefix match is
        // sufficient because macOS uses the same Bluetooth chip for both directions.
        let micBase = selectedMicID.components(separatedBy: ":").first ?? selectedMicID
        let outputBase = outputUID.components(separatedBy: ":").first ?? outputUID

        if micBase == outputBase {
            bluetoothRoutingConflict = true
            bluetoothRecommendation =
                "Using \(mic.name) as mic while it's also the audio output forces HFP mode (mono ~16 kHz). "
                    + "This is fine for speech recognition, but audio quality will drop. "
                    + "Switch to the built-in mic for higher quality, or continue if convenience matters more."
        } else {
            bluetoothRoutingConflict = false
            bluetoothRecommendation = nil
        }
    }

    /// Checks if a mic device UID is still present in the CoreAudio device list.
    func isMicStillAvailable(_ deviceUID: String) -> Bool {
        let discoverySession = AVCaptureDevice.DiscoverySession(
            deviceTypes: [.microphone, .external],
            mediaType: .audio,
            position: .unspecified
        )
        return discoverySession.devices.contains { $0.uniqueID == deviceUID }
    }

    /// Returns the UID of the current default output audio device.
    private static func defaultOutputDeviceUID() -> String? {
        var deviceID: AudioDeviceID = 0
        var size = UInt32(MemoryLayout<AudioDeviceID>.size)
        var address = AudioObjectPropertyAddress(
            mSelector: kAudioHardwarePropertyDefaultOutputDevice,
            mScope: kAudioObjectPropertyScopeGlobal,
            mElement: kAudioObjectPropertyElementMain
        )

        let status = AudioObjectGetPropertyData(
            AudioObjectID(kAudioObjectSystemObject),
            &address, 0, nil, &size, &deviceID
        )
        guard status == noErr else { return nil }

        address.mSelector = kAudioDevicePropertyDeviceUID
        var uid: Unmanaged<CFString>?
        size = UInt32(MemoryLayout<Unmanaged<CFString>?>.size)
        let uidStatus = AudioObjectGetPropertyData(
            deviceID, &address, 0, nil, &size, &uid
        )
        guard uidStatus == noErr, let uid = uid?.takeUnretainedValue() else { return nil }
        return uid as String
    }

    private var recordingsDirectory: URL {
        let dir = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
            .appendingPathComponent("MacOSSample-Recordings", isDirectory: true)
        try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        return dir
    }
}

// MARK: - UI State

enum RecordingUIState: Equatable, Sendable {
    case idle
    case recording
    case paused
}

// MARK: - Delegate Adapter

/// Bridges the non-isolated AudioCaptureDelegate callbacks to MainActor closures.
private final class CaptureDelegateAdapter: AudioCaptureDelegate, @unchecked Sendable {
    var onStateChange: (@Sendable (CaptureState) -> Void)?
    var onLevelsUpdate: (@Sendable (AudioLevels) -> Void)?
    var onError: (@Sendable (CaptureError) -> Void)?
    var onFinish: (@Sendable (RecordingResult) -> Void)?

    func captureSession(
        _: any AudioCaptureSession,
        didChangeState state: CaptureState
    ) {
        onStateChange?(state)
    }

    func captureSession(
        _: any AudioCaptureSession,
        didUpdateLevels levels: AudioLevels
    ) {
        onLevelsUpdate?(levels)
    }

    func captureSession(
        _: any AudioCaptureSession,
        didEncounterError error: CaptureError
    ) {
        onError?(error)
    }

    func captureSession(
        _: any AudioCaptureSession,
        didFinishCapture result: RecordingResult
    ) {
        onFinish?(result)
    }
}

// MARK: - Audio Player Delegate Adapter

private final class AudioPlayerDelegateAdapter: NSObject, AVAudioPlayerDelegate, @unchecked Sendable {
    var onFinish: (@Sendable () -> Void)?

    func audioPlayerDidFinishPlaying(_: AVAudioPlayer, successfully _: Bool) {
        onFinish?()
    }
}

// MARK: - Sendable Weak Reference

/// A Sendable wrapper for a weak reference to a MainActor-isolated object.
/// Used to safely pass a reference across concurrency boundaries (e.g. CoreAudio callbacks)
/// without triggering Swift 6 actor isolation traps.
private final class WeakSendableBox<T: AnyObject>: @unchecked Sendable {
    weak var value: T?
    init(_ value: T) {
        self.value = value
    }
}

